// Tuya → Supabase sensor_readings — LP&ET cron 4h
// Reemplazar las constantes con valores reales antes de activar el workflow.
const crypto = require('crypto');

const ACCESS_ID     = '__TUYA_ACCESS_ID__';
const ACCESS_SECRET = '__TUYA_ACCESS_SECRET__';
const BASE_URL      = 'https://openapi.tuyaus.com';
const DEVICE_ID     = '__TUYA_DEVICE_ID__';

const SUPABASE_URL  = '__SUPABASE_URL__';
const SUPABASE_KEY  = '__SUPABASE_SERVICE_OR_ANON_KEY__';
const TANK_ID       = '__TANK_UUID__';
const PH_OFFSET     = 0; // ajuste tras calibración

function sha256Hex(m){return crypto.createHash('sha256').update(m,'utf8').digest('hex');}
function hmacSha256(k,m){return crypto.createHmac('sha256',k).update(m,'utf8').digest('hex').toUpperCase();}

async function callTuya(method, path, accessToken){
  const t = Date.now().toString();
  const contentSha = sha256Hex('');
  const stringToSign = method + '\n' + contentSha + '\n\n' + path;
  const signStr = accessToken
    ? ACCESS_ID + accessToken + t + stringToSign
    : ACCESS_ID + t + stringToSign;
  const sign = hmacSha256(ACCESS_SECRET, signStr);
  const headers = { client_id: ACCESS_ID, sign, t, sign_method: 'HMAC-SHA256' };
  if (accessToken) headers.access_token = accessToken;
  return await this.helpers.httpRequest({ method, url: BASE_URL + path, headers, json: true });
}

const tokenRes = await callTuya.call(this, 'GET', '/v1.0/token?grant_type=1');
if (!tokenRes.success) return [{ json: { ok:false, error:'token_fail', detail: tokenRes } }];
const token = tokenRes.result.access_token;

const shadowRes = await callTuya.call(this, 'GET', '/v2.0/cloud/thing/' + DEVICE_ID + '/shadow/properties', token);
if (!shadowRes.success) return [{ json: { ok:false, error:'shadow_fail', detail: shadowRes } }];

const props = shadowRes.result.properties || [];
const byCode = Object.fromEntries(props.map(p => [p.code, p]));
const val = (c, s) => { const p = byCode[c]; return p ? p.value / s : null; };

const phRaw  = val('ph_current', 100);
const phAdj  = phRaw != null ? +(phRaw + PH_OFFSET).toFixed(2) : null;
const tempC  = val('temp_current', 10);
const orpMv  = val('orp_current', 1);
const sg     = val('pro_current', 1000);
const tdsPpm = val('tds_current', 1);
const ecUsCm = val('ec_current', 1);
const salPpm = val('salinity_current', 1);
const cf     = val('cf_current', 100);
const rhPct  = val('rh_current', 1);
// Brix legacy: aproximación desde SG
const brixApprox = sg != null ? +(((sg - 1) * 1000) / 4).toFixed(2) : null;

const payload = {
  tank_id: TANK_ID,
  ph: phAdj,
  temp_c: tempC,
  brix: brixApprox,
  orp_mv: orpMv,
  sg,
  tds_ppm: tdsPpm,
  ec_us_cm: ecUsCm,
  salinity_ppm: salPpm,
  cf,
  rh_pct: rhPct
};

const supaRes = await this.helpers.httpRequest({
  method: 'POST',
  url: SUPABASE_URL + '/rest/v1/sensor_readings',
  headers: {
    apikey: SUPABASE_KEY,
    Authorization: 'Bearer ' + SUPABASE_KEY,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: payload,
  json: true
});

return [{ json: {
  ok: true,
  fetched_at: new Date().toISOString(),
  payload,
  supabase_response: supaRes
}}];
